  if (govRefCount) { score += Math.min(4, govRefCount * 2); reasons.push(`Gov/Reform x${govRefCount} (+${Math.min(4, govRefCount*2)})`); }

  const hasUA = uaCount > 0;
  const keep =
    score >= THRESHOLD_KEEP ||
    (hasUA && score >= UA_ONLY_KEEP_MIN) ||           // Ukraine mention alone can pass
    (hasUA && (reconCount || donorCount || humCount)); // Ukraine + any strong theme

  const bucket =
    keep ? (reconCount ? "ua_recon" : humCount ? "ua_humanitarian" : "score_keep") : "drop";

  return { keep, score, bucket, reasons, domain };
}

// Evaluate all, but do NOT drop them yet
const all = $input.all();
const kept = [];

for (const item of all) {
  const res = evaluateItem(item);
  item.json.__decision = res.keep ? "keep" : "drop";
  item.json.__relevance_score = res.score;
  item.json.__relevance_bucket = res.bucket;
  item.json.__relevance_reasons = res.reasons;
  if (res.keep) kept.push(item);
}

// Fail-open: if we kept nothing, pass everything through so workflow continues
if (FAIL_OPEN && kept.length === 0) {
  for (const item of all) {
    item.json.__decision = "keep_fallback";
    item.json.__relevance_bucket = "fail_open";
    item.json.__relevance_reasons = ["Fail-open: kept=0, passing through all items"];
  }
  return all;
}

// Otherwise, return only kept (same behavior as before, but far less brittle)
return kept;

function stripFences(s) {
  return String(s || "")
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();
}

function safeParseJsonString(s) {
  const cleaned = stripFences(s);
  try {
    const parsed = JSON.parse(cleaned);
    // Must be an object
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) return parsed;
    return null;
  } catch {
    return null;
  }
}

// 1) Base item is always an object
const base = ($json && typeof $json === "object" && !Array.isArray($json)) ? $json : {};

// 2) AI output string (may be in output, text, response depending on your AI node)
const aiRaw = base.output ?? base.text ?? base.response ?? "";

// 3) Parse AI JSON string safely
const ai = safeParseJsonString(aiRaw) || {};

// 4) Build final object (MUST be an object)
const out = {
  title_uk: base.title_uk ?? "",
  summary_uk: base.summary_uk ?? "",

  title_en: ai.title_en ?? "",
  title_de: ai.title_de ?? "",
  summary_en: ai.summary_en ?? "",
  summary_de: ai.summary_de ?? "",

  primary_sector: ai.primary_sector ?? base.primary_sector ?? "infrastructure",
  translation_status: ai.translation_status ?? "machine",

  article_type: base.article_type ?? "news",
  published_date: base.published_date ?? new Date().toISOString(),
  source_url: base.source_url ?? "",
  source_id: base.source_id ?? null,
  secondary_sectors: Array.isArray(base.secondary_sectors) ? base.secondary_sectors : [],
  credibility_tier: Number.isFinite(base.credibility_tier) ? base.credibility_tier : 2,
  original_language: base.original_language ?? "uk",
  content_hash: base.content_hash ?? null,

  processing_status: base.processing_status ?? "ready_for_review",
  requires_review: base.requires_review ?? false
};

// 5) Enforce allowed sectors
const allowed = new Set(["housing","basic infrastructure","urban-resilience","disaster-risk management"]);
if (!allowed.has(out.primary_sector)) {
  out.primary_sector = "supply-infrastructure";
  out.requires_review = true;
  out.processing_status = "needs_enrichment";
  out.review_reason = "invalid_primary_sector_from_ai";
}

// 6) If AI fields missing, mark review but still return valid object
if (!out.title_en || !out.title_de || !out.summary_en || !out.summary_de) {
  out.requires_review = true;
  out.processing_status = "needs_enrichment";
  out.review_reason = out.review_reason ?? "ai_missing_required_fields";
}

// 7) CRITICAL: Always return json as an OBJECT
return [{ json: out }];

// Supabase "Get many rows" with Always Output Data ON can emit {} when no match.
// If a match exists, the returned item will contain at least content_hash or id.
// We produce a stable boolean flag.

const hasMatch =
  !!$json && typeof $json === "object" && (
    !!$json.id ||
    !!$json.content_hash ||
    !!$json.source_url
  );

return [{ json: { __is_duplicate: hasMatch } }];

return items.filter(item => {
  // Drop items that only contain the duplicate flag
  if (!item.json) return false;

  const keys = Object.keys(item.json);

  // If the item ONLY contains the duplicate flag, remove it
  if (keys.length === 1 && keys[0] === '__is_duplicate') {
    return false;
  }

  // Keep everything else
  return true;
});
